using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

// Find the background object
var bgObj = GameObject.Find("背景");
if (bgObj == null) { Debug.LogError("背景 not found"); return; }

// Find sprite assets
string slimeKingPath = "Assets/Layer Lab/2D Characters-CasualMonsters/PNG/All/green_slime/slime_king.png";
string goblinWarriorPath = "Assets/Layer Lab/2D Characters-CasualMonsters/PNG/All/goblin_green/goblin_warrior.png";

Sprite slimeSprite = AssetDatabase.LoadAssetAtPath<Sprite>(slimeKingPath);
Sprite goblinSprite = AssetDatabase.LoadAssetAtPath<Sprite>(goblinWarriorPath);

if (slimeSprite == null) { Debug.LogError("Slime sprite not found at: " + slimeKingPath); return; }
if (goblinSprite == null) { Debug.LogError("Goblin sprite not found at: " + goblinWarriorPath); return; }

// Create Slime King patrol enemy
GameObject slimeObj = new GameObject("Patrol_SlimeKing");
slimeObj.transform.SetParent(bgObj.transform, false);
RectTransform slimeRt = slimeObj.AddComponent<RectTransform>();
Image slimeImg = slimeObj.AddComponent<Image>();
slimeImg.sprite = slimeSprite;
slimeImg.SetNativeSize();
slimeImg.raycastTarget = false;
slimeRt.localScale = new Vector3(0.5f, 0.5f, 1f);
slimeRt.anchoredPosition = new Vector2(-400f, -150f);

var slimePatrol = slimeObj.AddComponent<TowerDefense.UI.UIPatrolEnemy>();
var slimeSerialized = new SerializedObject(slimePatrol);
slimeSerialized.FindProperty("_moveSpeed").floatValue = 60f;
slimeSerialized.FindProperty("_patrolMinX").floatValue = -600f;
slimeSerialized.FindProperty("_patrolMaxX").floatValue = 600f;
slimeSerialized.FindProperty("_patrolY").floatValue = -150f;
slimeSerialized.FindProperty("_bobSpeed").floatValue = 2.5f;
slimeSerialized.FindProperty("_bobAmount").floatValue = 10f;
slimeSerialized.FindProperty("_enemySprite").objectReferenceValue = slimeSprite;
slimeSerialized.ApplyModifiedProperties();

// Create Goblin Warrior patrol enemy
GameObject goblinObj = new GameObject("Patrol_GoblinWarrior");
goblinObj.transform.SetParent(bgObj.transform, false);
RectTransform goblinRt = goblinObj.AddComponent<RectTransform>();
Image goblinImg = goblinObj.AddComponent<Image>();
goblinImg.sprite = goblinSprite;
goblinImg.SetNativeSize();
goblinImg.raycastTarget = false;
goblinRt.localScale = new Vector3(0.4f, 0.4f, 1f);
goblinRt.anchoredPosition = new Vector2(300f, -100f);

var goblinPatrol = goblinObj.AddComponent<TowerDefense.UI.UIPatrolEnemy>();
var goblinSerialized = new SerializedObject(goblinPatrol);
goblinSerialized.FindProperty("_moveSpeed").floatValue = 80f;
goblinSerialized.FindProperty("_patrolMinX").floatValue = -700f;
goblinSerialized.FindProperty("_patrolMaxX").floatValue = 700f;
goblinSerialized.FindProperty("_patrolY").floatValue = -100f;
goblinSerialized.FindProperty("_bobSpeed").floatValue = 3f;
goblinSerialized.FindProperty("_bobAmount").floatValue = 6f;
goblinSerialized.FindProperty("_enemySprite").objectReferenceValue = goblinSprite;
goblinSerialized.ApplyModifiedProperties();

Debug.Log("Created patrol enemies: SlimeKing and GoblinWarrior");

